window.UK_PATHWAY_PROFILE = {"beccs":{"label":"BECCS (heat/electricity)","eff":0.8,"cost":"$200-225","needs_storage":true,"pros":["High CDR efficiency (~80%)","Energy co-product (heat/electricity) displaces fossil emissions","Low durability risk; Frontier's most-preferred pathway"],"cons":["Capital-intensive; works best at large scale","Not very modular \u2014 hard to deploy in distributed settings"]},"beccs_pp":{"label":"BECCS pulp & paper","eff":0.8,"cost":"$200-225","needs_storage":true,"pros":["Retrofits an existing pulp & paper mill \u2014 low execution risk, near-term","High CDR efficiency (~80%) from concentrated recovery-boiler flue gas","Leverages existing biomass logistics + grid connection"],"cons":["Requires an existing mill to retrofit","Capture capex on flue gas"]},"wte_ccs":{"label":"WtE + CCS","eff":0.55,"cost":"~$100-200","needs_storage":true,"pros":["Captures biogenic CO2 from municipal waste already being combusted","Energy co-product; handles MSW at urban scale"],"cons":["Only ~50-60% of flue-gas CO2 is biogenic (CDR efficiency ~55%)","Urban siting and public-acceptance hurdles"]},"lfg_ccs":{"label":"Landfill gas + CCS","eff":0.52,"cost":"$100-200","needs_storage":true,"pros":["Retrofits an existing landfill gas-collection system \u2014 near-term, low execution risk","Captures concentrated, ~100%-biogenic CO2 from combusted landfill gas","Energy co-product (electricity) and avoids fugitive methane (co-benefit)"],"cons":["Only the captured biogenic CO2 counts as removal \u2014 uncollected fugitive methane (gas collection ~75%) is a large asterisk on the claim","Dilute, variable gas stream; capture capex on a modest flue volume"]},"lfg_rng_ccs":{"label":"Landfill-gas RNG + CCS","eff":0.33,"cost":"$80-180","needs_storage":true,"pros":["Captures the near-pure CO2 already vented by landfill-gas-to-RNG upgrading \u2014 cheap capture","RNG co-product displaces fossil pipeline gas; retrofits an existing/planned RNG project","Avoids fugitive landfill methane (co-benefit)"],"cons":["Only the separated CO2 is removal; the RNG carbon is combusted downstream (avoidance, not CDR) \u2014 caps CDR efficiency","Depends on a gas-upgrading / RNG project being present or viable"]},"injection":{"label":"Biomass waste injection","eff":0.9,"cost":"$125-285","needs_storage":true,"pros":["Very high CDR efficiency (>90%)","Cheaper on balance than bio-oil where wells are near","PFAS destruction; disposes problematic wet wastes"],"cons":["No emissions-avoiding co-product","Hauling bulky, less-carbon-dense biomass is costly if wells are far"]},"bio_oil":{"label":"Bio-oil (pyrolysis)","eff":0.45,"cost":"$140-360","needs_storage":false,"pros":["Modular and distributed (Charm-style roving model)","Pyrolysis densifies the carbon, so it is cheap to haul to distant wells","Returns biochar and nutrients to fields","Low durability risk"],"cons":["Lower CDR efficiency (~45%)","Needs dry/solid biomass \u2014 not for wet feedstocks","Higher $/t than injection where storage is proximate"]},"bio_oil_htl":{"label":"Bio-oil (hydrothermal liquefaction)","eff":0.5,"cost":"$200-400","needs_storage":false,"pros":["Handles WET biomass (manure/biosolids) directly \u2014 no drying needed","Hydrothermal liquefaction densifies the carbon into a stable bio-crude, cheap to haul to distant wells","Viable where wet-slurry injection/AD would need nearby geologic storage"],"cons":["Higher cost and earlier-stage than pyrolysis or direct injection","Lower CDR efficiency than slurry injection (~50% vs >90%)"]},"burial":{"label":"Biomass burial","eff":0.9,"cost":"<$100-150","needs_storage":false,"pros":["Very high CDR efficiency (>90%)","Simple and low-cost; needs no geologic CO2 storage","Works for distributed biomass"],"cons":["Durability still being validated (Frontier prepurchase, not offtake)","No emissions-avoiding co-product; nutrient-export risk with ag residues"]},"ad_ccs":{"label":"AD + CCS","eff":0.37,"cost":"$145-300","needs_storage":true,"pros":["Suits wet feedstock; mature technology","Returns nutrients to fields","RNG co-product displaces fossil gas; viable offtake option"],"cons":["Low CDR efficiency (~30-44%)","Carbon is split between the RNG (fuel) and CDR streams, capping CDR"]},"biochar":{"label":"Biochar","eff":0.3,"cost":"~$100-200","needs_storage":false,"pros":["Returns nutrients to soils, improving yields","Distributed and storage-independent; simple and near-term"],"cons":["Low CDR efficiency (~30%)","Durability and verification questions; Frontier's lower-preference pathway"]}};
